prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?created ?org ?orgLabel WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "262d9e9b8c224d918fe800cd2a454ddf" .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:modelCreated ?created . }
  OPTIONAL {
    ?model tai:belongsTo ?org .
    OPTIONAL { ?org rdfs:label ?orgLabel . }
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?mfSource ?mfTarget ?msgRef WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "262d9e9b8c224d918fe800cd2a454ddf" .
  ?def tai:belongsTo ?model .
  ?choreo tai:belongsTo ?def .
  ?mf a bboExt:MessageFlow .
  ?mf tai:belongsTo ?choreo .
  OPTIONAL { ?mf bboExt:sourceRef ?mfSource . }
  OPTIONAL { ?mf bboExt:targetRef ?mfTarget . }
  OPTIONAL { ?mf bboExt:messageRef ?msgRef . }
  OPTIONAL { ?mf bbo:name ?mfName . }
}
